SELECT ?episode ?date WHERE {
  wd:Q128133 wdt:P144 ?series .
  ?series wdt:P31 wd:Q5398426 .
  ?episode wdt:P179 ?series ;
           wdt:P577 ?date .
  FILTER (?date > NOW())
}
ORDER BY ?date
LIMIT 1

