SELECT ?episode ?date WHERE {
  ?series wdt:P114 wd:Q128133 .
  {
    ?episode wdt:P179 ?series ;
           wdt:P577 ?date .
  }
  UNION
  {
    ?episode wdt:P179 ?series ;
           wdt:P1191 ?date .
  }
  FILTER (?date > NOW())
}
ORDER BY ?date
LIMIT 1

SELECT ?seriesLabel ?episodeLabel ?date WHERE {
  ?series wdt:P178 wd:Q128133 .
  ?series rdfs:label ?seriesLabel .
  ?episode wdt:P179 ?series ;
           wdt:P577 ?date ;
           rdfs:label ?episodeLabel .
  FILTER (?date > NOW())
  FILTER (LANG(?seriesLabel) = 'en' && LANG(?episodeLabel) = 'en')
}
ORDER BY ?date
LIMIT 1

